@startuml
class "Person" {
  [C]
  + id: Long
  + firstName: String
  + lastName: String
  + telNr: String
}

class "Booking" {
  [C]
  + id: Long
  + person: Person
  + trip: Trip
}

class "Trip" {
  [C]
  + id: Long
  + destination: Destination
  + bus: Bus
}

class "Bus" {
  [C]
  + id: Long
  + seats: int
}

class "Destination" {
  [C]
  + id: Long
  + street: String
  + streetNo: int
  + place: String
  + zip: int
}

Person "1" --> "*" Booking : bucht Reise (Trip)
Booking "*" --> "1" Trip : hat Buchungen
Trip "1" --> "1" Bus : Reise wird mit Bus durchgeführt
Trip "*" --> "1" Destination : Reise geht nach

@enduml
